(function()
{
    /*
     * 本地 WebView 使用 integrate.min.js 作为 draw.io 应用包。
     * 该包会引用云存储文件类型，但当前应用只启用本地嵌入编辑。
     * 这里提供最小构造函数，避免离线模式因未定义云存储类型而中断。
     */
    function ensureConstructor(name)
    {
        if (typeof window[name] !== 'function')
        {
            window[name] = function() {};
        }
    }

    [
        'DriveFile',
        'DriveLibrary',
        'DropboxFile',
        'DropboxLibrary',
        'OneDriveFile',
        'OneDriveLibrary',
        'GitHubFile',
        'GitHubLibrary',
        'GitLabFile',
        'GitLabLibrary',
        'TrelloFile',
        'TrelloLibrary'
    ].forEach(ensureConstructor);

    if (typeof window.OneDriveFile.prototype.getIdOf !== 'function')
    {
        window.OneDriveFile.prototype.getIdOf = function(value)
        {
            return value && (value.id || value.driveId || value.name) || '';
        };
    }
})();
